from haystack import component
import subprocess
import tempfile
import os

@component
class SandboxExecutor:
    @component.output_types(output=str, error=str)
    def run(self, code: str) -> dict:
        with tempfile.NamedTemporaryFile(mode='w', suffix='.py', delete=False) as f:
            f.write(code)
            filepath = f.name
        try:
            result = subprocess.run(['python', filepath], capture_output=True, text=True, timeout=30)
            os.unlink(filepath)
            return {'output': result.stdout, 'error': result.stderr}
        except subprocess.TimeoutExpired:
            os.unlink(filepath)
            return {'output': '', 'error': 'Execution timeout'}

sandbox = SandboxExecutor()

from haystack import component
import pytest
import sys

@component
class TestValidator:
    @component.output_types(passed=bool, failures=list)
    def validate(self, code: str, tests: str) -> dict:
        with tempfile.NamedTemporaryFile(mode='w', suffix='.py') as code_file, \
             tempfile.NamedTemporaryFile(mode='w', suffix='_test.py') as test_file:
            code_file.write(code)
            code_file.flush()
            test_file.write(tests)
            test_file.flush()
            sys.path.insert(0, os.path.dirname(code_file.name))
            result = pytest.main([test_file.name, '-v', '--tb=short'])
        return {'passed': result == 0, 'failures': []}

