from haystack import component
from vex_sdk import VexClient, VerificationSuite

@component
class VexVerifier:
    def __init__(self):
        self.vex = VexClient(api_key='your-vex-key')
        self.suite = VerificationSuite(
            checks=['code_correctness', 'security_vuln_scan', 'no_credential_leak', 'dependency_safety']
        )

    @component.output_types(verified=bool, issues=list)
    def verify(self, code: str, context: list) -> dict:
        report = self.vex.verify(self.suite, {'code': code, 'repo_context': context})
        return {'verified': report.passed, 'issues': report.issues}

vex_verifier = VexVerifier()
code_assist_pipe.add_component('vex', vex_verifier)
code_assist_pipe.connect('generator', 'vex')

from vex_sdk import RiskProfile

vex_config = {
    'risk_profile': RiskProfile.MEDIUM,
    'block_on': ['security_vulnerability', 'credential_leak'],
    'warn_on': ['license_compliance', 'dependency_safety'],
    'timeout': 30
}

@component
class ConfiguredVex:
    def __init__(self, config: dict):
        self.vex = VexClient(api_key='your-key', config=config)

    def run_pipeline_with_vex(self, pipeline_result: dict) -> dict:
        verified = self.vex.verify_suite(pipeline_result['code'], vex_config)
        if not verified.passed:
            raise ValueError(f'Verification failed: {verified.issues}')
        return pipeline_result

pipe_with_vex = Pipeline().add_component('vex_guard', ConfiguredVex(vex_config))
